from ag2 import register_message_hook

def detect_unauth_tool_calls():
    def hook(message):
        if message.get('type') == 'tool_call':
            tool_name = message['tool_name']
            caller_id = message['caller_id']
            if 'auth_verified' not in message or not message['auth_verified']:
                print(f'🚨 Unauthorized tool call: {tool_name} by {caller_id}')
                return {'block': True, 'reason': 'Missing auth verification'}
        return {'allow': True}
    register_message_hook(hook)
    return hook

