import jwt
from ag2 import register_message_hook

SECRET_KEY = 'your-secret-key'

def ag2_auth_middleware():
    def validate_jwt(token):
        try:
            return jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        except:
            return None

    def auth_hook(message):
        token = message.get('auth_token')
        if not token:
            return {'block': True, 'error': 'Missing auth token'}

        payload = validate_jwt(token)
        if not payload or payload['agent_id'] != message['sender']:
            return {'block': True, 'error': 'Invalid auth token'}

        message['auth_verified'] = True
        return {'allow': True}

    register_message_hook(auth_hook)
    return auth_hook

from ag2.groupchat import GroupChatManager

class SecureSpeakerManager(GroupChatManager):
    def __init__(self, role_permissions):
        self.role_permissions = role_permissions

    def select_speaker(self, context):
        candidates = self.get_candidates(context)
        for agent in candidates:
            required_role = context.get('required_role')
            if self.has_permission(agent, required_role):
                return agent
        raise PermissionError('No authorized speaker available')

    def has_permission(self, agent, role):
        return role in self.role_permissions.get(agent.name, [])

