from ag2 import Agent
from typing import Dict, List

class AuthenticatedAgent(Agent):
    def __init__(self, name, auth_token, permissions: List[str]):
        super().__init__(name)
        self.auth_token = auth_token
        self.permissions = permissions

    def send_message(self, content, recipient):
        if not self.verify_permissions(content):
            raise PermissionError(f'{self.name} lacks permissions')

        message = {
            'sender': self.name,
            'content': content,
            'auth_token': self.auth_token,
            'permissions': self.permissions
        }
        return super().send_message(message, recipient)

    def verify_permissions(self, content):
        if 'tool_call' in content:
            tool = content['tool_call']['name']
            return tool in self.permissions
        return True

