from ag2 import GroupChat, register_message_hook

# Install: pip install ag2 vex-sdk
vex = Vex(api_key='your-vex-key')

@vex.register_detector('ag2-auth-failures')
def scan_ag2_auth_issues(messages):
    failures = []
    for msg in messages:
        if msg.get('type') == 'agent_message':
            if not msg.get('auth_verified'):
                failures.append({
                    'type': 'missing_auth',
                    'agent': msg['sender'],
                    'message_id': msg['id']
                })
    return {
        'score': len(failures),
        'issues': failures,
        'remediation': 'block_unauthenticated_agents'
    }

# Auto-register Vex as AG2 message hook
register_message_hook(vex.ag2_hook())

# Start monitoring
vex.start_monitoring()
